import React from 'react';

interface ProgressBarProps {
  current: number;
  total: number;
}

const ProgressBar: React.FC<ProgressBarProps> = ({ current, total }) => {
  const percentage = Math.round((current / total) * 100);

  return (
    <section className="mb-8 glass-card p-6 rounded-2xl relative overflow-hidden group">
      {/* Decorative top border with gradient */}
      <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-green-500 via-white to-red-500 opacity-50"></div>

      <div className="flex justify-between items-end mb-4 relative z-10">
        <div>
          <h2 className="text-xs font-bold uppercase tracking-widest text-green-400 mb-1">Daily Goal</h2>
          <p className="text-3xl font-bold text-white">
            {current}/{total} <span className="text-base font-medium text-gray-400 ml-1">Lessons</span>
          </p>
        </div>
        <div className="px-3 py-1 rounded-full bg-white/10 border border-white/10 text-xs font-bold text-white">
          {percentage}%
        </div>
      </div>

      <div className="w-full bg-gray-700/50 h-4 rounded-full overflow-hidden backdrop-blur-sm border border-white/5">
        <div 
          className="italian-gradient h-full rounded-full transition-all duration-1000 ease-out shadow-[0_0_15px_rgba(255,255,255,0.3)]" 
          style={{ width: `${percentage}%` }}
        ></div>
      </div>

      <p className="mt-4 text-sm text-gray-300 font-medium flex items-center gap-2">
        <span className="material-symbols-outlined text-yellow-400 text-lg fill">local_fire_department</span>
        {total - current} more to hit your streak!
      </p>
    </section>
  );
};

export default ProgressBar;

