const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<NavItem>(NavItem.HOME);

  const renderContent = () => {
    switch (activeTab) {
      case NavItem.HOME:
        return (
          <>
            <ProgressBar current={3} total={5} />

            <div className="flex items-center justify-between mb-5 relative z-10">
              <h2 className="text-xl font-bold text-white">Vocabulary Packs</h2>
              <button className="text-sm font-semibold text-green-400 hover:text-green-300 transition-colors">
                View All
              </button>
            </div>

            <div className="grid grid-cols-2 gap-4 relative z-10">
              {VOCABULARY_PACKS.map((pack) => (
                <VocabularyCard key={pack.id} {...pack} />
              ))}
              <ConversationCard {...CONVERSATION_PACK} />
            </div>
          </>
        );
      case NavItem.LESSONS:
        return (
          <div className="flex flex-col items-center justify-center py-20 text-center glass-card rounded-2xl p-8">
            <span className="material-symbols-outlined text-6xl text-gray-500 mb-4">auto_stories</span>
            <h2 className="text-2xl font-bold mb-2">My Lessons</h2>
            <p className="text-gray-400">Continue your journey through the Italian language. More levels coming soon.</p>
          </div>
        );
      case NavItem.PROFILE:
        return (
          <div className="flex flex-col items-center justify-center py-20 text-center glass-card rounded-2xl p-8">
            <span className="material-symbols-outlined text-6xl text-gray-500 mb-4">person_celebrate</span>
            <h2 className="text-2xl font-bold mb-2">Student Profile</h2>
            <p className="text-gray-400">View your achievements, badges, and language streaks.</p>
          </div>
        );
    }
  };

  return (
    <div className="min-h-screen flex flex-col antialiased bg-[#1a1f2e] text-white selection:bg-green-500/30">
      <Header />

      <main className="flex-1 px-6 pb-28 pt-6 relative overflow-hidden">
        {/* Background Decorative Elements */}
        <div className="absolute top-0 left-[-20%] w-[60%] h-[400px] bg-green-500/10 rounded-full blur-[100px] pointer-events-none"></div>
        <div className="absolute bottom-20 right-[-10%] w-[50%] h-[300px] bg-red-500/10 rounded-full blur-[100px] pointer-events-none"></div>

        {renderContent()}
      </main>

      <Navbar activeTab={activeTab} onTabChange={setActiveTab} />
    </div>
  );
};

export default App;

