import React, { useState } from 'react';
import { VocabularyPack } from '../types';
import { GoogleGenAI, Modality } from "@google/genai";

interface CategoryDetailProps {
  pack: VocabularyPack;
  onBack: () => void;
}

// Helper functions for audio processing as per Gemini API guidelines
function decodeBase64(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

const CategoryDetail: React.FC<CategoryDetailProps> = ({ pack, onBack }) => {
  const [playingIndex, setPlayingIndex] = useState<number | null>(null);

  const playPronunciation = async (text: string, index: number) => {
    if (playingIndex !== null) return;

    setPlayingIndex(index);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text: `Pronuncia chiaramente in italiano: ${text}` }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName: 'Kore' },
            },
          },
        },
      });

      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (base64Audio) {
        const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        const audioBuffer = await decodeAudioData(
          decodeBase64(base64Audio),
          audioContext,
          24000,
          1,
        );
        const source = audioContext.createBufferSource();
        source.buffer = audioBuffer;
        source.connect(audioContext.destination);
        source.onended = () => {
          setPlayingIndex(null);
        };
        source.start();
      } else {
        setPlayingIndex(null);
      }
    } catch (error) {
      console.error("Failed to generate pronunciation:", error);
      setPlayingIndex(null);
    }
  };

  return (
    <div className="animate-in fade-in slide-in-from-right-4 duration-300">
      <div className="flex items-center gap-4 mb-8">
        <button 
          onClick={onBack}
          className="w-10 h-10 rounded-full glass-card flex items-center justify-center hover:bg-white/10 transition-colors"
        >
          <span className="material-symbols-outlined text-white">arrow_back</span>
        </button>
        <div>
          <h2 className="text-2xl font-bold text-white">{pack.title}</h2>
          <p className="text-gray-400 text-sm">{pack.subtitle}</p>
        </div>
      </div>

      <div className="relative rounded-3xl overflow-hidden mb-8 h-48 group shadow-2xl">
        <img 
          src={pack.imageUrl} 
          alt={pack.title}
          className="w-full h-full object-cover brightness-50 group-hover:scale-105 transition-transform duration-1000"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-[#1a1f2e] via-transparent to-transparent"></div>
        <div className="absolute bottom-6 left-6">
          <span className="material-symbols-outlined text-green-400 text-4xl mb-2">{pack.icon}</span>
          <p className="text-white/60 text-sm font-medium">Learning {pack.items.length} words in this pack</p>
        </div>
      </div>

      <div className="space-y-3 pb-8">
        {pack.items.map((item, index) => (
          <div 
            key={index}
            onClick={() => playPronunciation(item.italian, index)}
            className="glass-card p-5 rounded-2xl flex items-center justify-between group hover:bg-white/10 transition-all cursor-pointer border border-white/5 active:scale-[0.98]"
            style={{ animationDelay: `${index * 50}ms` }}
          >
            <div>
              <p className="text-lg font-bold text-white group-hover:text-green-400 transition-colors">{item.italian}</p>
              <p className="text-sm text-gray-400">{item.english}</p>
            </div>
            <button 
              className={`w-10 h-10 rounded-full flex items-center justify-center transition-all duration-300 ${
                playingIndex === index 
                ? 'bg-green-500 text-white' 
                : 'bg-white/5 text-gray-400 group-hover:bg-green-500/20 group-hover:text-green-400'
              }`}
            >
              <span className={`material-symbols-outlined text-xl ${playingIndex === index ? 'animate-pulse' : ''}`}>
                {playingIndex === index ? 'graphic_eq' : 'volume_up'}
              </span>
            </button>
          </div>
        ))}
      </div>
    </div>
  );
};

