              >
                <span className={`material-symbols-outlined text-3xl ${isCurrent ? 'animate-pulse' : ''}`}>
                  {isCurrent ? 'graphic_eq' : 'replay'}
                </span>
              </button>
            </div>
          );
        })}
      </div>
    </div>
  );
};

