            <span className="material-symbols-outlined text-white">arrow_back</span>
          </button>
          <div>
            <h2 className="text-2xl font-bold text-white tracking-tight">{pack.title}</h2>
            <p className="text-gray-400 text-sm font-medium">{pack.subtitle}</p>
